// serve registers whatever the caller binds and returns the connection, so all
// three services share one setup path.
func serve(t *testing.T, register func(s grpc.ServiceRegistrar)) *grpc.ClientConn {
	t.Helper()
	lis, err := net.Listen("tcp", "127.0.0.1:0")
	if err != nil {
		t.Fatal(err)
	}
	s := grpc.NewServer()
	register(s)
	go s.Serve(lis)
	t.Cleanup(s.Stop)

	cc, err := grpc.NewClient(lis.Addr().String(), grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		t.Fatal(err)
	}
	t.Cleanup(func() { cc.Close() })
	return cc
}

func TestProductServiceRoundTrip(t *testing.T) {
	cc := serve(t, func(s grpc.ServiceRegistrar) {
		RegisterProductServiceServer(s, &testProductServer{})
	})
	c := NewProductServiceClient(cc)
	ctx := context.Background()

	if got, err := c.GetProduct(ctx, &GetProductRequest{Id: 5}); err != nil || got.GetId() != 5 {
		t.Errorf("GetProduct = %v, %v", got, err)
	}
	if got, err := c.ListProducts(ctx, &ListProductsRequest{}); err != nil || got.GetTotal() != 1 {
		t.Errorf("ListProducts = %v, %v", got, err)
	}

	stream, err := c.WatchProducts(ctx, &ListProductsRequest{})
	if err != nil {
		t.Fatal(err)
	}
	if _, err := stream.Recv(); err != nil {
		t.Errorf("WatchProducts: %v", err)
	}
}

func TestOrderServiceRoundTrip(t *testing.T) {
	cc := serve(t, func(s grpc.ServiceRegistrar) {
		RegisterOrderServiceServer(s, &testOrderServer{})
	})
	c := NewOrderServiceClient(cc)
	ctx := context.Background()

	if got, err := c.PlaceOrder(ctx, &PlaceOrderRequest{UserId: 3}); err != nil || got.GetUserId() != 3 {
		t.Errorf("PlaceOrder = %v, %v", got, err)
	}
	if got, err := c.GetOrder(ctx, &GetOrderRequest{Id: 8}); err != nil || got.GetId() != 8 {
		t.Errorf("GetOrder = %v, %v", got, err)
	}
}

// The Unimplemented embeds for the other two services must answer the same way.
func TestOtherServicesUnimplemented(t *testing.T) {
	pcc := serve(t, func(s grpc.ServiceRegistrar) {
		RegisterProductServiceServer(s, &UnimplementedProductServiceServer{})
	})
	pc := NewProductServiceClient(pcc)
	ctx := context.Background()

	if _, err := pc.GetProduct(ctx, &GetProductRequest{}); status.Code(err) != codes.Unimplemented {
		t.Errorf("GetProduct: code = %v, want Unimplemented", status.Code(err))
	}
	if _, err := pc.ListProducts(ctx, &ListProductsRequest{}); status.Code(err) != codes.Unimplemented {
		t.Errorf("ListProducts: code = %v, want Unimplemented", status.Code(err))
	}
	if stream, err := pc.WatchProducts(ctx, &ListProductsRequest{}); err == nil {
		if _, err := stream.Recv(); status.Code(err) != codes.Unimplemented {
			t.Errorf("WatchProducts: code = %v, want Unimplemented", status.Code(err))
		}
	}

	occ := serve(t, func(s grpc.ServiceRegistrar) {
		RegisterOrderServiceServer(s, &UnimplementedOrderServiceServer{})
	})
	oc := NewOrderServiceClient(occ)
	if _, err := oc.PlaceOrder(ctx, &PlaceOrderRequest{}); status.Code(err) != codes.Unimplemented {
		t.Errorf("PlaceOrder: code = %v, want Unimplemented", status.Code(err))
	}
	if _, err := oc.GetOrder(ctx, &GetOrderRequest{}); status.Code(err) != codes.Unimplemented {
		t.Errorf("GetOrder: code = %v, want Unimplemented", status.Code(err))
	}
}

func TestAllServiceDescs(t *testing.T) {
	cases := []struct {
		desc    grpc.ServiceDesc
		name    string
		methods int
		streams int
	}{
		{UserService_ServiceDesc, "shop.v1.UserService", 4, 1},
		{ProductService_ServiceDesc, "shop.v1.ProductService", 2, 1},
		{OrderService_ServiceDesc, "shop.v1.OrderService", 2, 0},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			if tc.desc.ServiceName != tc.name {
				t.Errorf("name = %q, want %q", tc.desc.ServiceName, tc.name)
			}
			if len(tc.desc.Methods) != tc.methods {
				t.Errorf("methods = %d, want %d", len(tc.desc.Methods), tc.methods)
			}
			if len(tc.desc.Streams) != tc.streams {
				t.Errorf("streams = %d, want %d", len(tc.desc.Streams), tc.streams)
			}
		})
	}
}

// Each generated handler has two paths: a direct call when no interceptor is
// installed, and a wrapped one when there is. Both must reach the service.
func TestHandlersRunUnderInterceptors(t *testing.T) {
	var unaryCalls, streamCalls int

	lis, err := net.Listen("tcp", "127.0.0.1:0")
	if err != nil {
		t.Fatal(err)
	}
	s := grpc.NewServer(
		grpc.UnaryInterceptor(func(ctx context.Context, req any, info *grpc.UnaryServerInfo, h grpc.UnaryHandler) (any, error) {
			unaryCalls++
			return h(ctx, req)
		}),
		grpc.StreamInterceptor(func(srv any, ss grpc.ServerStream, info *grpc.StreamServerInfo, h grpc.StreamHandler) error {
			streamCalls++
			return h(srv, ss)
		}),
	)
	RegisterUserServiceServer(s, &testServer{})
	RegisterProductServiceServer(s, &testProductServer{})
	RegisterOrderServiceServer(s, &testOrderServer{})
	go s.Serve(lis)
	defer s.Stop()

	cc, err := grpc.NewClient(lis.Addr().String(), grpc.WithTransportCredentials(insecure.NewCredentials()))
	if err != nil {
		t.Fatal(err)
	}
	defer cc.Close()
	ctx := context.Background()

	uc := NewUserServiceClient(cc)
	if _, err := uc.GetUser(ctx, &GetUserRequest{Id: 1}); err != nil {
		t.Errorf("GetUser: %v", err)
	}
	if _, err := uc.ListUsers(ctx, &ListUsersRequest{}); err != nil {
		t.Errorf("ListUsers: %v", err)
	}
	if _, err := uc.CreateUser(ctx, &CreateUserRequest{}); err != nil {
		t.Errorf("CreateUser: %v", err)
	}
	if _, err := uc.DeleteUser(ctx, &DeleteUserRequest{}); err != nil {
		t.Errorf("DeleteUser: %v", err)
	}

	pc := NewProductServiceClient(cc)
	if _, err := pc.GetProduct(ctx, &GetProductRequest{}); err != nil {
		t.Errorf("GetProduct: %v", err)
	}
	if _, err := pc.ListProducts(ctx, &ListProductsRequest{}); err != nil {
		t.Errorf("ListProducts: %v", err)
	}

	oc := NewOrderServiceClient(cc)
	if _, err := oc.PlaceOrder(ctx, &PlaceOrderRequest{}); err != nil {
		t.Errorf("PlaceOrder: %v", err)
	}
	if _, err := oc.GetOrder(ctx, &GetOrderRequest{}); err != nil {
		t.Errorf("GetOrder: %v", err)
	}

	// Streaming handlers go through the stream interceptor instead.
	if st, err := uc.StreamUsers(ctx, &ListUsersRequest{}); err != nil {
		t.Errorf("StreamUsers: %v", err)
	} else {
		for {
			if _, err := st.Recv(); err != nil {
				break
			}
		}
	}
	if st, err := pc.WatchProducts(ctx, &ListProductsRequest{}); err != nil {
		t.Errorf("WatchProducts: %v", err)
	} else {
		for {
			if _, err := st.Recv(); err != nil {
				break
			}
		}
	}

	if unaryCalls != 8 {
		t.Errorf("unary interceptor ran %d times, want 8", unaryCalls)
	}
	if streamCalls != 2 {
		t.Errorf("stream interceptor ran %d times, want 2", streamCalls)
	}
}
